#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int **adj;
    int *color;
    int numVertices;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adj = (int**) malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adj[i] = (int*) malloc(numVertices * sizeof(int));
    }
    graph->color = (int*) malloc(numVertices * sizeof(int));
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u][v] = 1;
    graph->adj[v][u] = 1;
}

// Function to check if the graph is bipartite
int isBipartite(Graph* graph) {
    for (int i = 0; i < graph->numVertices; i++) {
        if (graph->color[i] == -1) {
            if (!bfs(graph, i)) {
                return 0;
            }
        }
    }
    return 1;
}

// Function to perform BFS
int bfs(Graph* graph, int start) {
    graph->color[start] = 1;
    int *queue = (int*) malloc(graph->numVertices * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < graph->numVertices; v++) {
            if (graph->adj[u][v] && graph->color[v] == -1) {
                graph->color[v] = 1 - graph->color[u];
                queue[rear++] = v;
            } else if (graph->adj[u][v] && graph->color[v] == graph->color[u]) {
                return 0;
            }
        }
    }
    return 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        Graph* graph = createGraph(n);
        for (int i = 0; i < n; i++) {
            graph->color[i] = -1;
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(graph, u - 1, v - 1);
        }
        if (isBipartite(graph)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

