#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a graph
struct Graph {
    vector<vector<int>> adj;
    vector<int> color;
    int numVertices;
};

// Function to create a graph
Graph createGraph(int numVertices) {
    Graph graph;
    graph.numVertices = numVertices;
    graph.adj.resize(numVertices, vector<int>(numVertices, 0));
    graph.color.resize(numVertices, -1);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v) {
    graph.adj[u][v] = 1;
    graph.adj[v][u] = 1;
}

// Function to check if the graph is bipartite
bool isBipartite(Graph& graph) {
    for (int i = 0; i < graph.numVertices; i++) {
        if (graph.color[i] == -1) {
            if (!bfs(graph, i)) {
                return false;
            }
        }
    }
    return true;
}

// Function to perform BFS
bool bfs(Graph& graph, int start) {
    graph.color[start] = 1;
    vector<int> queue;
    queue.push_back(start);
    while (!queue.empty()) {
        int u = queue[0];
        queue.erase(queue.begin());
        for (int v = 0; v < graph.numVertices; v++) {
            if (graph.adj[u][v] && graph.color[v] == -1) {
                graph.color[v] = 1 - graph.color[u];
                queue.push_back(v);
            } else if (graph.adj[u][v] && graph.color[v] == graph.color[u]) {
                return false;
            }
        }
    }
    return true;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, m;
        cin >> n >> m;
        Graph graph = createGraph(n);
        for (int i = 0; i < m; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(graph, u - 1, v - 1);
        }
        if (isBipartite(graph)) {
            cout << "YES" << endl;
        } else {
            cout << "NO" << endl;
        }
    }
    return 0;
}

