    static class Graph {
        int[][] adj;
        int[] color;
        int numVertices;
    }

    // Function to create a graph
    public static Graph createGraph(int numVertices) {
        Graph graph = new Graph();
        graph.numVertices = numVertices;
        graph.adj = new int[numVertices][numVertices];
        graph.color = new int[numVertices];
        for (int i = 0; i < numVertices; i++) {
            graph.color[i] = -1;
        }
        return graph;
    }

    // Function to add an edge to the graph
    public static void addEdge(Graph graph, int u, int v) {
        graph.adj[u][v] = 1;
        graph.adj[v][u] = 1;
    }

    // Function to check if the graph is bipartite
    public static boolean isBipartite(Graph graph) {
        for (int i = 0; i < graph.numVertices; i++) {
            if (graph.color[i] == -1) {
                if (!bfs(graph, i)) {
                    return false;
                }
            }
        }
        return true;
    }

    // Function to perform BFS
    public static boolean bfs(Graph graph, int start) {
        graph.color[start] = 1;
        int[] queue = new int[graph.numVertices];
        int front = 0, rear = 0;
        queue[rear++] = start;
        while (front < rear) {
            int u = queue[front++];
            for (int v = 0; v < graph.numVertices; v++) {
                if (graph.adj[u][v] == 1 && graph.color[v] == -1) {
                    graph.color[v] = 1 - graph.color[u];
                    queue[rear++] = v;
                } else if (graph.adj[u][v] == 1 && graph.color[v] == graph.color[u]) {
                    return false;
                }
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            Graph graph = createGraph(n);
            for (int i = 0; i < m; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                addEdge(graph, u, v);
            }
            if (isBipartite(graph)) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

