from collections import deque

# Structure to represent a graph
class Graph:
    def __init__(self, numVertices):
        self.numVertices = numVertices
        self.adj = [[0 for _ in range(numVertices)] for _ in range(numVertices)]
        self.color = [-1 for _ in range(numVertices)]

# Function to add an edge to the graph
def addEdge(graph, u, v):
    graph.adj[u][v] = 1
    graph.adj[v][u] = 1

# Function to check if the graph is bipartite
def isBipartite(graph):
    for i in range(graph.numVertices):
        if graph.color[i] == -1:
            if not bfs(graph, i):
                return False
    return True

# Function to perform BFS
def bfs(graph, start):
    graph.color[start] = 1
    queue = deque([start])
    while queue:
        u = queue.popleft()
        for v in range(graph.numVertices):
            if graph.adj[u][v] == 1 and graph.color[v] == -1:
                graph.color[v] = 1 - graph.color[u]
                queue.append(v)
            elif graph.adj[u][v] == 1 and graph.color[v] == graph.color[u]:
                return False
    return True

# Main function
if __name__ == '__main__':
    t = int(input())
    for _ in range(t):
        n, m = map(int, input().split())
        graph = Graph(n)
        for _ in range(m):
            u, v = map(int, input().split())
            addEdge(graph, u - 1, v - 1)
        if isBipartite(graph):
            print('YES')
        else:
            print('NO')

