        let color = new Array(n).fill(-1);
        for (let i = 0; i < m; i++) {
            let [u, v] = input.shift().split(' ').map(Number);
            graph[u - 1][v - 1] = 1;
            graph[v - 1][u - 1] = 1;
        }
        if (isBipartite(graph, color)) {
            console.log('YES');
        } else {
            console.log('NO');
        }
    }
});

function isBipartite(graph, color) {
    for (let i = 0; i < graph.length; i++) {
        if (color[i] == -1) {
            if (!bfs(graph, color, i)) {
                return false;
            }
        }
    }
    return true;
}

function bfs(graph, color, start) {
    color[start] = 1;
    let queue = [start];
    while (queue.length > 0) {
        let u = queue.shift();
        for (let v = 0; v < graph.length; v++) {
            if (graph[u][v] == 1 && color[v] == -1) {
                color[v] = 1 - color[u];
                queue.push(v);
            } else if (graph[u][v] == 1 && color[v] == color[u]) {
                return false;
            }
        }
    }
    return true;
}

